//verifica id da sessao.
verificaidsessao.Call(&DevRandon, &IsAcessoConcedido, &IsAtualizaTudo, &wwpContext)

if &IsAcessoConcedido = true
	if not &codigoBarras.IsEmpty()
		RetornaProdutoReferencia.Call(&wwpContext.EmpCod, &codigoBarras, &OutProCod, &ProGraCod, &ProNom, &IsAchouProduto, &ProReqVlr, &ProReqQtd, &ProBarQtd, &ErroMensagem)

		if &IsAchouProduto = false
			&sdtConsultaEstoque.Sts = 'E003'
			&sdtConsultaEstoque.Obs = 'Produto não localizado'

			do 'PrecoVazio'

			do 'addSemImagem'		
			Return
		Endif	
	Else
		&sdtConsultaEstoque.Sts = 'E002'
		&sdtConsultaEstoque.Obs = 'Nenhum produto informado'
		do 'precoVazio'
		do 'addSemImagem'
		Return
	EndIF

	&sdtConsultaEstoque.Sts = 'J200'
	&sdtConsultaEstoque.ProNom = &ProNom

	//	&EstUltSai.SetEmpty()
	//	&EstSug.SetEmpty()
	&EstSdo = 0
	//	&EstPrd = 0
    &EstQtd = 0 
	//	&EstABC_Ren = 'D'
	//	&EstABC_Qtd = 'D'
	//	&EstLoc = ''
	&TabCod = ''
	//	&ProIsGra = false
	//	&VarCharIMC = ''
	//	&ProIMC = 0
	//	&ProSolLot = SolicitarLote.NAO_CONTROLAR
	&OutProCodEstCod.SetEmpty()
	//	&ProQtdEmb.SetEmpty()
	//	&ProUltAtuCalMin.SetEmpty()

	//	txtinfor.Caption = ''
	For Each Order EmpCod, ProCod
		Where EmpCod = &wwpContext.EmpCod
		Where ProCod = &OutProCod
		Where ProGraCod = &ProGraCod

		&sdtConsultaEstoque.ProGraRef = ProGraRef
		//
		//		&ProIsGra = ProIsGra
		//		&ProSolLot = ProSolLot
		//		&ProNom = ProNomGra
		//		&ProTipDef = ProTipDef
		&sdtConsultaEstoque.ProEmbUnd = ProEmbUnd
		//		&ProIMC = ProIMC
		&sdtConsultaEstoque.ProVlrCus = ProVlrCus
		&OutProCodEstCod = ProEstProCod
		//		&ProQtdEmb = ProQtdEmb
		//		&ProUltAtuCalMin = ProUltAtuCalMin
		//		
		RetornaImagemPrincipal180_URI.Call(&wwpContext.EmpCod, &OutProCod, TipoImagemProduto.IMAGEM_VENDA, &sdtConsultaEstoque.LinkImgProduto, &IsSemImagem)

		//		RetornaImagemPrincipal180.Call(&wwpContext.EmpCod, &OutProCod, TipoImagemProduto.IMAGEM_PRODUCAO, &ProImg180_Producao, &IsSemImagem)
		//		
		//		tbImagemProducao.Visible = (&INDAGRIL = 'S' or &IsSemImagem = false)
		//		
		For Each Estoque Order EmpCod, FilCod, ProCod, ProGraCod
		    Where FilCod = &wwpContext.FilCod

			if ProEstTip = tipoestoque.ATUALIZAR_ESTOQUE or ProEstTip.IsEmpty() or ProEstTip.IsNull()
				&EstSdo = EstSdo
				&EstQtd = EstQtd
			Endif

			//			&EstPrd = EstPrd
			//			&EstABC_Qtd = EstABC_Qtd
			//			&EstABC_Ren = EstABC_Ren
			//			
			If Not EstLoc.IsEmpty()
				&sdtConsultaEstoque.EstLoc = EstLoc
			Else
				&sdtConsultaEstoque.EstLoc = 'SEM_LOCAÇÃO'
			EndIF

			&LocacaoExtraMensagem.SetEmpty()
			For each Order EmpCod, FilCod, ProCod, ProGraCod, EstLocExt	
				if &LocacaoExtraMensagem.IsEmpty()
					&LocacaoExtraMensagem += EstLocExt.Trim()
				Else
					&LocacaoExtraMensagem += ' / '+EstLocExt.Trim()
				Endif
			EndFor
			&sdtConsultaEstoque.EstLocPul = &LocacaoExtraMensagem

			//			&EstMin = EstMin
			//			if not EstMinIni.IsEmpty() and not EstMinIni.IsNull()
			//				txtinfor.Caption = format('Apuração: %1-%2', EstMinIni.ToFormattedString(),EstMinFin.ToFormattedString())
			//			Endif
			//		
			//			&EstSug = EstSug
			//			
			&TabCod = FilTabCod
			//			
			//			&EstUltEnt = EstUltEnt
			//			&EstUltFab = EstUltFab
			//			&EstUltSai = EstUltSai
			//			
			//			&txtVenda = EstVen
			//			&txtCompra = EstCom
		When none
			iniciaEstoque.Call( &wwpContext.EmpCod, &wwpContext.FilCod, &OutProCod, &ProGraCod)
	    EndFor

	When none
		&sdtConsultaEstoque.Sts = 'E003'
		&sdtConsultaEstoque.Obs = 'Produto não localizado'
		do 'addSemImagem'
		Return
	EndFor

	if &OutProCodEstCod <> &OutProCod
		For Each Order EmpCod, ProCod
			Where EmpCod = &wwpContext.EmpCod
			Where ProCod = &OutProCodEstCod
			Where ProGraCod = &ProGraCod

			&sdtConsultaEstoque.EstOutProduto = 'ESTOQUE: ' + trim(ProGraRefNom)

			For Each Estoque Order EmpCod, FilCod, ProCod, ProGraCod
			    Where FilCod = &wwpContext.FilCod

				&EstSdo = EstSdo
				&EstQtd = EstQtd
				exit
			When none
				iniciaEstoque.Call( &wwpContext.EmpCod, &wwpContext.FilCod, &OutProCodEstCod, &ProGraCod)
		    EndFor
			Exit
		EndFor
	Endif
	//
	//	If &EstABC_Ren.IsEmpty()
	//		&EstABC_Ren = 'D'
	//	EndIF
	//
	//	If &EstABC_Qtd.IsEmpty()
	//		&EstABC_Qtd = 'D'
	//	EndIf
	//	
	//    &CalcProIMC = 0 
	//	&auxTabPrc1 = 0
	//	&TabPrc1.Clear()

	RetornaColunas_Nome.Call(&wwpContext.EmpCod, &TabCod, &SdtColunasTabela)

    For Each Order EmpCod, TabCod, ProCod, ProGraCod, (TabAltCod)
		Where EmpCod = &wwpContext.EmpCod
		Where TabCod = &TabCod
	    Where ProCod = &OutProCod
		Where ProGraCod = &ProGraCod

		if &SdtColunasTabela.Tem1 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 1
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom1
			&sdtConsultaEstoqueItem.valor =  TabPrc1
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		if &SdtColunasTabela.Tem2 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 2
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom2
			&sdtConsultaEstoqueItem.valor =  TabPrc2
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		if &SdtColunasTabela.Tem3 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 3
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom3
			&sdtConsultaEstoqueItem.valor =  TabPrc3
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		if &SdtColunasTabela.Tem4 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 4
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom4
			&sdtConsultaEstoqueItem.valor =  TabPrc4
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		if &SdtColunasTabela.Tem5 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 5
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom5
			&sdtConsultaEstoqueItem.valor =  TabPrc5
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		if &SdtColunasTabela.Tem6 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 6
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom6
			&sdtConsultaEstoqueItem.valor =  TabPrc6
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		if &SdtColunasTabela.Tem7 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 7
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom7
			&sdtConsultaEstoqueItem.valor =  TabPrc7
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		if &SdtColunasTabela.Tem8 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 8
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom8
			&sdtConsultaEstoqueItem.valor =  TabPrc8
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		if &SdtColunasTabela.Tem9 = 1
			&sdtConsultaEstoqueItem = new()
			&sdtConsultaEstoqueItem.colcod = 9
			&sdtConsultaEstoqueItem.coluna = &SdtColunasTabela.TabColNom9
			&sdtConsultaEstoqueItem.valor =  TabPrc9
			&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
		Endif

		Exit
	When none
		&sdtConsultaEstoqueItem = new()
		&sdtConsultaEstoqueItem.colcod = 0
		&sdtConsultaEstoqueItem.coluna = 'Preço não Cadastrado'
		&sdtConsultaEstoqueItem.valor  =  0
		&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)

    EndFor


	//
	//    if &auxTabPrc1 <> 0 
	//        &CalcProIMC = 100 - ((&ProVlrCus /&auxTabPrc1) * 100)
	//    EndIf
	//
	//	tbProducao.Visible = &EstPrd > 0 or not &EstUltFab.IsEmpty()
	//	&VarCharIMC = trim(toformattedString(&ProIMC)) + ' / ' + trim(ToformattedString(&CalcProIMC))
	&sdtConsultaEstoque.EstQtd = trim(RetiraZerosDepoisVirgulaxCasas.Udp(0, &EstQtd.ToFormattedString()))

	//	&VarcharEstMin = RetiraZerosDepoisVirgulaxCasas.Udp(0, &EstMin.ToFormattedString())
	&sdtConsultaEstoque.EstSdo = trim(RetiraZerosDepoisVirgulaxCasas.Udp(0, &EstSdo.ToFormattedString()))
	//&sdtConsultaEstoque.EstSug = RetiraZerosDepoisVirgulaxCasas.Udp(0, &EstSug.ToFormattedString())

	//	If &ProIsGra = true		
	//		wcEstoqueVariacao.Object = wcEstoqueVariacoes.Create(&wwpContext.EmpCod, &wwpContext.FilCod, &OutProCod, &ProGraCod)
	//		GXUITabsPanel_abaDadosEstoque.ShowTab(2)
	//		GXUITabsPanel_abaDadosEstoque.SelectTab(2)
	//	EndIF
	//	
	//	If &ProSolLot = SolicitarLote.SIM_CONTROLAR
	//		wwcLotesdoProduto.Object = wcEstoqueLotes.Create(&wwpContext.EmpCod, &wwpContext.FilCod, &OutProCod, &ProGraCod)
	//		GXUITabsPanel_abaDadosEstoque.ShowTab(3)
	//	Endif
	//	if &Context.EmpresaAcesso.Count <> 0
	//		wwcEmpresaAcesso.Object = wcEmpresaEstoques.create(&EmpCnpj, &ProCod, &OutProCod)
	//	Endif
	//	
	//	wcPedidossEstoque.Object = wcPedidosEstoque.Create(&wwpContext.EmpCod, &wwpContext.FilCod, &OutProCod, &ProGraCod)
Endif

sub 'precovazio'
	&sdtConsultaEstoqueItem = new()
	&sdtConsultaEstoqueItem.colcod = 1
	&sdtConsultaEstoqueItem.coluna = ''
	&sdtConsultaEstoqueItem.valor =  0
	&sdtConsultaEstoque.precos.Add(&sdtConsultaEstoqueItem)
EndSub

sub 'addSemImagem'
	For Each Order EmpCod
		Where EmpCod = &wwpContext.EmpCod
		&sdtConsultaEstoque.LinkImgProduto =  EmpDirVir.Trim() + '/' + Produto_Sem_Imagem180.Link()
		Exit
	EndFor
EndSub
